namespace sv_9f6ecc65372a4880bc4def292f901ad0.Client.Services;

public interface IShipmentService
{
    Task<ShipmentDetails> GetShipmentAsync(string trackingNumber, CancellationToken ct);
}

public record ShipmentDetails(
    string TrackingNumber,
    string Status,
    string Location,
    DateTimeOffset EstimatedDelivery,
    IReadOnlyList<StatusUpdate> StatusUpdates);

public record StatusUpdate(DateTimeOffset Timestamp, string Description, string Location);

using System.Net.Http.Json;

namespace sv_9f6ecc65372a4880bc4def292f901ad0.Client.Services;

public class HttpShipmentService : IShipmentService
{
    private readonly HttpClient _http;

    public HttpShipmentService(HttpClient http)
    {
        _http = http;
    }

    public async Task<ShipmentDetails> GetShipmentAsync(string trackingNumber, CancellationToken ct)
    {
        var response = await _http.GetAsync($"api/shipments/{Uri.EscapeDataString(trackingNumber)}", ct);
        response.EnsureSuccessStatusCode();
        return (await response.Content.ReadFromJsonAsync<ShipmentDetails>(ct))!;
    }
}

using sv_9f6ecc65372a4880bc4def292f901ad0.Client.Services;

namespace sv_9f6ecc65372a4880bc4def292f901ad0.Services;

public class ServerShipmentService : IShipmentService
{
    private static readonly Dictionary<string, ShipmentDetails> SeedData = new(StringComparer.OrdinalIgnoreCase)
    {
        ["PKG-001"] = new ShipmentDetails(
            "PKG-001",
            "In Transit",
            "Chicago, IL",
            DateTimeOffset.UtcNow.AddDays(2),
            new List<StatusUpdate>
            {
                new(DateTimeOffset.UtcNow.AddDays(-3), "Package picked up", "New York, NY"),
                new(DateTimeOffset.UtcNow.AddDays(-2), "Departed facility", "New York, NY"),
                new(DateTimeOffset.UtcNow.AddDays(-1), "Arrived at sorting center", "Chicago, IL"),
            }),
        ["PKG-002"] = new ShipmentDetails(
            "PKG-002",
            "Delivered",
            "San Francisco, CA",
            DateTimeOffset.UtcNow.AddDays(-1),
            new List<StatusUpdate>
            {
                new(DateTimeOffset.UtcNow.AddDays(-5), "Package picked up", "Seattle, WA"),
                new(DateTimeOffset.UtcNow.AddDays(-4), "Departed facility", "Seattle, WA"),
                new(DateTimeOffset.UtcNow.AddDays(-2), "Out for delivery", "San Francisco, CA"),
                new(DateTimeOffset.UtcNow.AddDays(-1), "Delivered", "San Francisco, CA"),
            }),
        ["PKG-003"] = new ShipmentDetails(
            "PKG-003",
            "Processing",
            "Dallas, TX",
            DateTimeOffset.UtcNow.AddDays(5),
            new List<StatusUpdate>
            {
                new(DateTimeOffset.UtcNow.AddHours(-6), "Label created", "Dallas, TX"),
            }),
    };

    public async Task<ShipmentDetails> GetShipmentAsync(string trackingNumber, CancellationToken ct)
    {
        await Task.Delay(1500, ct);

        if (SeedData.TryGetValue(trackingNumber, out var shipment))
        {
            return shipment;
        }

        throw new KeyNotFoundException($"Shipment '{trackingNumber}' not found.");
    }
}

@page "/shipments/{TrackingNumber}"
@rendermode InteractiveAuto
@using sv_9f6ecc65372a4880bc4def292f901ad0.Client.Services
@inject IShipmentService ShipmentService
@inject ILogger<Shipment> Logger
@implements IDisposable

<PageTitle>Shipment @TrackingNumber</PageTitle>

@if (_loading)
{
    <div class="loading-placeholder">
        <p>Loading shipment details for <strong>@TrackingNumber</strong>...</p>
    </div>
}
else if (_errorMessage is not null)
{
    <div class="error-container">
        <p class="error-message">@_errorMessage</p>
        <button @onclick="RetryAsync">Retry</button>
    </div>
}
else if (_shipment is not null)
{
    <h2>Shipment @_shipment.TrackingNumber</h2>
    <dl>
        <dt>Status</dt>
        <dd>@_shipment.Status</dd>
        <dt>Location</dt>
        <dd>@_shipment.Location</dd>
        <dt>Estimated Delivery</dt>
        <dd>@_shipment.EstimatedDelivery.ToString("f")</dd>
    </dl>

    <h3>Status Updates</h3>
    <ul>
        @foreach (var update in _shipment.StatusUpdates)
        {
            <li>
                <strong>@update.Timestamp.ToString("g")</strong> &mdash; @update.Description (@update.Location)
            </li>
        }
    </ul>
}

@code {
    [Parameter]
    public string TrackingNumber { get; set; } = default!;

    private ShipmentDetails? _shipment;
    private bool _loading;
    private string? _errorMessage;
    private CancellationTokenSource? _cts;

    protected override async Task OnParametersSetAsync()
    {
        await LoadShipmentAsync();
    }

    private async Task LoadShipmentAsync()
    {
        // Cancel any in-flight request
        _cts?.Cancel();
        _cts?.Dispose();
        _cts = new CancellationTokenSource();
        var ct = _cts.Token;

        _loading = true;
        _errorMessage = null;
        _shipment = null;
        StateHasChanged();

        try
        {
            _shipment = await ShipmentService.GetShipmentAsync(TrackingNumber, ct);
        }
        catch (OperationCanceledException) when (ct.IsCancellationRequested)
        {
            // Navigation changed or component disposed; do nothing
            return;
        }
        catch (TaskCanceledException ex) when (ex.InnerException is TimeoutException || !ct.IsCancellationRequested)
        {
            Logger.LogError(ex, "Timeout loading shipment {TrackingNumber}", TrackingNumber);
            _errorMessage = "The request timed out. Please try again.";
        }
        catch (TimeoutException ex)
        {
            Logger.LogError(ex, "Timeout loading shipment {TrackingNumber}", TrackingNumber);
            _errorMessage = "The request timed out. Please try again.";
        }
        catch (Exception ex)
        {
            Logger.LogError(ex, "Error loading shipment {TrackingNumber}", TrackingNumber);
            _errorMessage = "Something went wrong loading shipment details. Please try again.";
        }
        finally
        {
            _loading = false;
            StateHasChanged();
        }
    }

    private async Task RetryAsync()
    {
        await LoadShipmentAsync();
    }

    public void Dispose()
    {
        _cts?.Cancel();
        _cts?.Dispose();
    }
}

